1) Do not ignore duplicate entries.
2) If cache size N is reached, FIFO implementation should pop the first element from the cache for every new entry.

Using DoublyLinkedList, we can remove any element in O(1). Note: The code is not tested, it is to give you the idea
```
    static class Cache {
        int capacity;
        Map<String, DLinkedList> map;
        int cSize;
        DLinkedList head;
        DLinkedList tail;
        static class DLinkedList {
            String key;
            DLinkedList prev;
            DLinkedList next;
        }

        public Cache(int n) {
            this.capacity = n;
            this.cSize = 0;
            map = new HashMap<>();
            head = new DLinkedList();
            tail = new DLinkedList();
            head.next = tail;
            tail.prev = head;
        }

        void add(String element) {
            // Implement constant-time here.
            if (!map.containsKey(element)) {
                if (cSize == capacity) {
                    DLinkedList node = removeFromTail();
                    map.remove(node.key);
                    cSize--;
                }
                DLinkedList node = new DLinkedList();
                node.key = element;
                addNode(node);
                map.put(element,node);
                cSize++;
            }
        }

        boolean contains(String element) {
            // Implement constant-time here.
            return !map.containsKey(element);
        }

        void remove(String element) {
            // Implement constant-time here.
            DLinkedList node = map.get(element);
            if (node == null) return;
            deleteNode(node);
            map.remove(element);
        }

        private void addNode(DLinkedList node) {
            node.prev = head;
            node.next = head.next;
            node.next.prev = node;
            node.prev.next = node;
        }

        private DLinkedList removeFromTail() {
            DLinkedList node = tail.prev;
            deleteNode(node);
            return node;
        }

        private void deleteNode(DLinkedList node) {
            node.next.prev = node.prev;
            node.prev.next = node.next;
            node.next = null;
            node.prev = null;
        }
    }

import java.util.HashMap;
import java.util.LinkedList;
import java.util.Map;

class Node {
    String value;
    Node prev, next;

    public Node(String value) {
        this.value = value;
        this.prev = this.next = null;
    }
}

class Cache {
    private int capacity;
    private Map<String, LinkedList<Node>> map;
    private Node head, tail;
    private int size;

    public Cache(int capacity) {
        this.capacity = capacity;
        this.map = new HashMap<String, LinkedList<Node>>();
        this.head = this.tail = null;
        this.size = 0;
    }

    public void add(String element) {
        if (size == capacity) {
            // Remove oldest element
            String valToRemove = head.value;
            removeFromList(head);
            removeFromMap(valToRemove);
        }
        Node node = new Node(element);
        addLast(node);
        addInMap(element, node);
    }

    private void removeFromMap(String value) {
        LinkedList<Node> nodes = map.get(value);
        if (nodes != null) {
            nodes.removeLast();
            if (nodes.isEmpty()) {
                map.remove(value);
            }
        }
    }

    private void addInMap(String value, Node node) {
        if (!map.containsKey(value)) {
            map.put(value, new LinkedList<Node>());
        }
        map.get(value).add(node);
    }

    private void removeFromList(Node node) {
        if (node == head && node == tail) {
            head = tail = null;
        } else if (node == head) {
            head = head.next;
            head.prev = null;
        } else if (node == tail) {
            tail = tail.prev;
            tail.next = null;
        } else {
            node.prev.next = node.next;
            node.next.prev = node.prev;
        }
        size--;
    }

    private void addLast(Node node) {
        if (tail == null) {
            head = tail = node;
        } else {
            tail.next = node;
            node.prev = tail;
            tail = node;
        }
        size++;
    }

    public void remove(String element) {
        LinkedList<Node> nodes = map.get(element);
        if (nodes != null) {
            for (Node node : nodes) {
                removeFromList(node);
            }
            map.remove(element);
        }
    }

    public boolean contains(String element) {
        return map.containsKey(element);
    }
}

public class ScratchPad {
    public static void main(String[] args) {
        Cache cache = new Cache(2);
        cache.add("10");
        cache.add("20");
        cache.add("30");
        cache.add("40");
