public class Cache {

    class Node {
        String value;
        Node prev;
        Node next;
    }

    private final HashMap<String, List<Node>> map;
    private final int maxSize;

    private Node first;
    private Node last;
    private int size;

    public Cache(int n) {
        maxSize = n;
        map = new HashMap<>(maxSize);
    }

    void add(String element) {
        if (size == maxSize) {
            Node toRemove = first;
            // remove from list
            removeFromList(toRemove);
            // remove node from map
            List<Node> nodes = map.get(toRemove.value);
            Iterator<Node> iterator = nodes.iterator();
            while (iterator.hasNext()) {
                Node cur = iterator.next();
                if (cur == toRemove) {
                    iterator.remove();
                    break;
                }
            }
            if (nodes.size() == 0) {
                map.remove(toRemove.value);
            }
        }
        Node node = new Node();
        node.value = element;
        // add into list
        addLast(node);
        // add node into map
        List<Node> nodes = map.get(element);
        if (nodes == null) {
            nodes = new ArrayList<>(1);
            map.put(element, nodes);
        }
        nodes.add(node);
    }

    private void addLast(Node node) {
        if (last == null) {
            first = last = node;
        } else {
            last.next = node;
            node.prev = last;
            last = node;
        }
        size++;
    }

    private void removeFromList(Node toRemove) {
        if (toRemove == last && toRemove == first) {
            last = first = null;
        } else if (toRemove == first) {
            first = first.next;
            first.prev = null;
        } else if (toRemove == last) {
            last = last.prev;
            last.next = null;
        } else {
            toRemove.prev.next = toRemove.next;
            toRemove.next.prev = toRemove.prev;
        }
        size--;
    }

    boolean contains(String element) {
        return map.containsKey(element);
    }

    void remove(String element) {
        List<Node> nodes = map.get(element);
        if (nodes != null) {
            // remove from map
            map.remove(element);
            for (Node node : nodes) {
                removeFromList(node);
            }
        }
    }

}
