Here is my solution in C++: 
```
using namespace std;
using sList = list<string>;
using iMap = unordered_map<string, list<sList::iterator>>;

class Cache{
    iMap _map;
    sList _fifo;
    const int _size;

public:
    Cache(const int size): _size(size), _fifo(){};

    void remove (const string& element){
        auto find = _map.find(element);
        // if it exists
        if(find != _map.end()){
            for(auto it : find->second){
                _fifo.erase(it);
            }
            _map.erase(find);
        }
        // otherwise nothing to remove
    }

    void add(const string& element){
        // if list is full, remove one
        if(_fifo.size() == _size){
            auto last = _fifo.front();
            sList::iterator lasti = _fifo.begin();
            _fifo.pop_front();

            auto find = _map.find(last);
//            if(find  == _map.end()) //error
            find->second.remove(lasti);
        }
        // otherwise it's ok to add
        _fifo.push_back(element);
        _map[element] = list<sList::iterator>({std::prev(_fifo.end())});
    }

    bool contains (const string& element){
        auto find = _map.find(element);
        return find != _map.end();
    }
};
